function ModelItem:OnModelInit()
    self:InintKeyListByType()
    self:InitItemRewardShowRef()
    self:InitItemHeroFreeAttrRef()
    self:ModelNetMsgRecv(LProtoIds.ItemListResp, function(...)
        self:OnItemListResp(...)
    end)
    self:ModelNetMsgRecv(LProtoIds.ItemUseResp, function(...)
        self:OnItemUseResp(...)
    end)
    self:ModelNetMsgRecv(LProtoIds.ItemChangeResp, function(...)
        self:OnItemChangeResp(...)
    end)
    self:ModelNetMsgRecv(LProtoIds.HeroSkinUseResp, function(...)
        self:OnHeroSkinUseResp(...)
    end)
    self:ModelNetMsgRecv(LProtoIds.ItemCallResultResp, function(...)
        self:OnItemCallResultResp(...)
    end)

    self:ModelNetMsgRecv(LProtoIds.Item146CallResultResp, function(...)
        self:OnItem146CallResultResp(...)
    end)

    self:SplitQualityRef()
end

function ModelItem:OnItem146CallResultResp(pb)
    local result = {
        index = pb.index,
        reward = pb.reward,
        select = 0,
        rankValue = pb.rankValue,
    }

    local refId = pb.refId
    local id = pb.id
    local itemdata = self:FormatItemUniqueData(refId, id)

    local wndpara = {
        result = result,
        itemdata = itemdata,
        round = pb.round,
        wndType = 2,
    }
    GF.OpenWnd("UILotteryRltsPop", wndpara)
end

