function ModelItem:SplitQualityRef()
    local qualityList = self._qualityList
    if not qualityList then
        qualityList = {}
        self._qualityList = qualityList
    end
    for k, v in pairs(GameTable.RarityRef) do
        local refId = v.refId
        local heroStarQuality = v.heroStarQuality
        qualityList[refId] = heroStarQuality
    end
end

function ModelItem:UpdateItemFilterList(refId, num, item)
    if self._yinghunList and self._yinghunList[refId] then
        if num > 0 then
            self._bagYingHunList[refId] = num
        else
            self._bagYingHunList[refId] = nil
        end
    end
    if self._runeItemList and self._runeItemList[refId] then
        if num > 0 then
            self._bagRuneItemList[refId] = num
        else
            self._bagRuneItemList[refId] = nil
        end
    end
    if self._badgeItemList and self._badgeItemList[refId] then
        if num > 0 then
            self._bagBadgeItemList[refId] = {num = num,quality = self._badgeItemList[refId].quality}
        else
            self._bagBadgeItemList[refId] = nil
        end
    end
    -- if self._upOutfitList and self._upOutfitList[refId] then
    -- 	if num > 0 then
    -- 		self._bagUpOutfitList[refId] = num
    -- 	else
    -- 		self._bagUpOutfitList[refId] = nil
    -- 	end
    -- end
    if self._upOutfitMaterialsList and self._upOutfitMaterialsList[refId] then
        if num > 0 then
            self._bagUpOutfitMaterialsList[refId] = num
        else
            self._bagUpOutfitMaterialsList[refId] = nil
        end
    end
    if self._leidengItemList and self._leidengItemList[refId] then
        if num > 0 then
            local bagExtraItemList = {}
            self._bagExtraItemList[refId] = bagExtraItemList
            local tData = item
            if tData then
                local tItem = tData:GetItemExtras()
                for idx, info in ipairs(tItem) do
                    local id = info.id
                    bagExtraItemList[id] = {
                        id = id,
                        createTime = info.createTime,
                        type = info.type,
                        rewardDays = info.rewardDays,
                        rewardDaysKey = info.rewardDaysKey,
                    }
                end
            end
        else
            self._bagExtraItemList[refId] = nil
        end
    end

    -- 【C宠物系统】删掉宠物系统相关
