function ModelItem:OnItemListResp(pb, ret)
    local itemList = {}
    self._itemList = itemList
    local mainCityTipsData = {}                                      --主城限时道具到期提醒
    local reminder = {
        [ModelItem.Item_Summon] = function(endTime, curTime, data, itemExtra)
            --134
            local cTime = (tonumber(endTime) / 1000 - curTime) / 3600
            if cTime <= 24 then
                --if true then
                local _data = {
                    refId = data.refId,
                    id = itemExtra.id,
                    tipIndex = 53403
                }
                return _data
            end
        end,
        [ModelItem.ITEM_WISH_MATCH] = function(endTime, curTime, data, itemExtra, itemExtras)
            --144
            for i, v in ipairs(itemExtras) do
                local extraData = v
                local timeSpan = tonumber(endTime) / 1000 - curTime
                local timeBool = timeSpan <= gModelWishingMatch:GetMainCityTipsEndTime()
                if (timeBool) then
                    local extra = JSON.decode(extraData.extra)
                    local rewardCfg = gModelWishingMatch:GetConfigByTypeAndKey(ModelWishingMatch.Item, extraData.refId)
                    local todayDrawBool = extra.dayNum < rewardCfg.dayDropNum
                    if (not todayDrawBool) then
                        return
                    end
                    local _data = {
                        refId = data.refId,
                        id = extraData.id,
                        tipIndex = 361101,
                        extra = extra
                    }
                    return _data
                end
            end
        end
    }
    local datas = pb.data
    local item
    for i = 1, #datas do
        local data = datas[i]
        local refId = data.refId

        if not gModelFunctionOpen:CheckRefDisable(ModelFunctionOpen.ITEM, refId) then
            ---地区屏蔽 物品不进背包
            local itemExtras = data.itemExtras
            local itemExtra = itemExtras[1]

            if itemExtra and reminder[itemExtra.type] and not mainCityTipsData[itemExtra.type] then
                local extra = JSON.decode(itemExtra.extra)
                local endTime = extra.endTime
                if not string.isempty(endTime) then
                    local curTime = GetTimestamp()
                    mainCityTipsData[itemExtra.type] = reminder[itemExtra.type](endTime, curTime, data, itemExtra,
                            itemExtras)
                end
            end

            local refId = data.refId
            local num = tonumber(data.num)
            if num ~= 0 then
                item = itemList[refId]
                if not item then
                    item = StructItem:New()
                    itemList[refId] = item
                end
                item:CreateByPb(data)
            end
            self:UpdateItemFilterList(refId, num, item)
        end
    end

    for i, v in pairs(mainCityTipsData) do
        local isAlert = gModelGeneral:FindAlertId(v.tipIndex)
        if not isAlert then
            local name = self:GetNameByRefId(v.refId)
            gModelWndPop:TryOpenPopWnd("UIOrdinTip", {
                refId = v.tipIndex,
                para = { name },
                func = function()
                    gModelGeneral:OpenItemInfoTip(v.refId, nil, nil, nil, nil, nil, nil, nil, v.id, nil, nil, nil, nil, v)
                end
            })
        end
    end
    FireEvent(EventNames.On_Hero_Change, true)
end

