function ModelItem:GetItemListByItemType(type, isSort)
    local list = {}
    local ItemRef = GameTable.PlayerItemRef
    for refId, v in pairs(self._itemList) do
        if ItemRef[refId] and ItemRef[refId].type == type then
            table.insert(list, v)
        end
    end

    if isSort then
        table.sort(list, function(a, b)
            local refA = ItemRef[a:GetRefId()]
            local refB = ItemRef[b:GetRefId()]
            if refA.quality ~= refB.quality then
                return refA.quality > refB.quality
            end
            return refA.refId < refB.refId
        end)
    end

    return list
end

