function ModelItem:CheckIsTryHeroCanAutoUse(refId)
    local tempItemType = self:GetType(refId)
    local canAutoUse = false
    local listData
    local isTryHeroType = tempItemType == ModelItem.Item_SELECT_TRY_HERO or
            tempItemType == ModelItem.Item_SELECT_TRY_SPIRITHERO
    if isTryHeroType then
        listData = self:GetTryHeroTypeRefListData(refId)
        if listData then
            canAutoUse = #listData == 1
        end
    end
    return canAutoUse, listData
end

function ModelItem:OnItemChangeResp(pb, ret)
    local itemList = self._itemList
    if not itemList then
        itemList = {}
        self._itemList = itemList
    end

    local changeAutoUseList = {}
    local oldNum, loseNum
    local num, refId, itemData, data, _type
    local item
    local isTryHeroItemCanAutoUse = false
    local listData

    local changeIdMap = {}
    local change = pb.change
    for i = 1, #change do
        data = change[i]
        _type = data.syncType
        itemData = data.item
        refId = itemData.refId

        if not gModelFunctionOpen:CheckRefDisable(ModelFunctionOpen.ITEM, refId) then
            ---地区屏蔽 物品不进背包
            oldNum = self:GetNumByRefId(refId, true)
            isTryHeroItemCanAutoUse, listData = self:CheckIsTryHeroCanAutoUse(refId)

            num = tonumber(itemData.num)
            loseNum = num - oldNum

            item = itemList[refId]

            local updateNum = num
            changeIdMap[refId] = true

            if _type == 1 then
                --新增
                if not item then
                    item = StructItem:New()
                    itemList[refId] = item
                end
                item:CreateByPb(itemData)

                if loseNum > 0 and isTryHeroItemCanAutoUse then
                    table.insert(changeAutoUseList, {
                        refId = refId, num = loseNum, listData = listData
                    })
                end
            elseif _type == 2 then
                --删除
                itemList[refId] = nil

                updateNum = 0
            elseif _type == 3 then
                -- 覆盖
                if num == 0 then
                    itemList[refId] = nil
                else
                    if not item then
                        item = StructItem:New()
                        itemList[refId] = item
                    end
                    item:CreateByPb(itemData)

                    if loseNum > 0 and isTryHeroItemCanAutoUse then
                        table.insert(changeAutoUseList, {
                            refId = refId, num = loseNum, listData = listData
                        })
                    end
                end
            end

            self:UpdateItemFilterList(refId, updateNum, item)
        end
    end

    self:AutoUseTryHeroList(changeAutoUseList)

    FireEvent(EventNames.On_Item_Change, changeIdMap)
    FireEvent(EventNames.On_HERO_OPT)
end

--- 自动使用126/129类型道具
function ModelItem:AutoUseTryHeroList(changeAutoUseList)
    if #changeAutoUseList < 1 then
        return
    end
    local list = {}
    local refId, num, listData
    local firstData
    for i, v in ipairs(changeAutoUseList) do
        listData = v.listData
        if #listData > 0 then
            firstData = listData[1]
            if firstData then
                refId, num = v.refId, v.num
                table.insert(list, {
                    refId = refId,
                    num = num,
                    params = tostring(firstData.heroRefId)
                })
            end
        end
    end
    if #list < 1 then
        return
    end
    self:OnItemUseReq(list)
end

-- Item:10=1,11=1; Hero:10=1;Drop:10=1
function ModelItem:OnItemUseResp(pb, ret)
    local syncType = pb.syncType
    local things = pb.things
    if not string.isempty(things) then
        local itemList = {}
        local rewardList = string.split(things, ",")
        for i, v in ipairs(rewardList) do
            local reward = string.split(v, "=")
            local typeNum = tonumber(reward[1])
            local itype = typeNum
            local refId = tonumber(reward[2])
            local num = tonumber(reward[3])
            if typeNum == 1 then
                itemList[#itemList + 1] = {
                    itype = itype,
                    itemId = refId,
                    count = num,
                }
            elseif typeNum == 2 then
                for heroNum = 1, num do
                    itemList[#itemList + 1] = {
                        itype = itype,
                        itemId = refId,
                        count = 1,
                    }
                end
            end
        end
        gModelWndPop:TryOpenPopWnd("UIAward", { itemList = itemList })
    end
end

