function ModelItem:ClearNewItemList()
    local infoList = {}
    for k, v in pairs(self._itemList) do
        local serverData = self:GetHeroServerDataByRefId(k)
        if serverData then
            local state = serverData.state
            if state == ModelItem.ITEM_NEW_STATUS then
                local refId = serverData.refId
                table.insert(infoList, {
                    type = LItemTypeConst.TYPE_ITEM,
                    refId = refId,
                    state = 0,
                })
            end
        end
    end
    local runeList = gModelRune:GetClearNewList()
    for i, v in ipairs(runeList) do
        local id = v.id
        table.insert(infoList, {
            type = LItemTypeConst.TYPE_RUNE,
            refId = v.refId,
            id = id,
            state = 0,
        })
    end
    if #infoList > 0 then
        local t = {}
        local index = 0
        for i, v in ipairs(infoList) do
            table.insert(t, v)
            index = index + 1
            if index >= 100 then
                self:OnDataStateChangeReq(t)
                index = 0
                t = {}
            end
        end
        if index ~= 0 then
            self:OnDataStateChangeReq(t)
        end
    end
end

function ModelItem:OnDataStateChangeReq(infoList)
    local pb = LProtoHelper.CreateProto(LProtoIds.DataStateChangeReq)
    local dataStateInfo = pb.dataStateInfo
    for i, v in ipairs(infoList) do
        local dataState = dataStateInfo:add()
        local itype = v.type
        dataState.type = itype
        dataState.refId = v.refId
        dataState.state = v.state
        if v.id then
            dataState.id = v.id
        end
        if itype == LItemTypeConst.TYPE_ITEM then
            self:ChangeStateByRefId(v.refId)
        elseif itype == LItemTypeConst.TYPE_RUNE then
            gModelRune:ChangeStateById(v.id)
        end
    end
    SendMessage(pb, LProtoIds.DataStateChangeReq)
end

