function ModelItem:GetNumByRefId(refId, justOneRef, itemType)
    if (itemType and itemType == LItemTypeConst.TYPE_HERO) then
        local beCapableOfHeroList = gModelHeroExtra:GetBeCapableOfSellHeroIdList(refId)
        return #beCapableOfHeroList
    end
    local itemList = self._itemList
    if not itemList then
        return 0
    end

    --- 对日本地区，增加免费钻石和充值钻石功能
    if gLGameLanguage:IsJapanRegion()
            and refId == ModelItem.ITEM_DIAMOND then
        return self:GetMasonryNum(justOneRef)
    end

    local serData = itemList[refId]
    if serData then
        return tonumber(serData:GetNum()) or 0
    end
    return 0
end

function ModelItem:GetMasonryNum(justOneRef)
    local itemList = self._itemList
    if not itemList then
        return 0
    end

    local num = 0
    local serData = itemList[ModelItem.ITEM_DIAMOND]
    if serData then
        num = tonumber(serData:GetNum()) or 0
    end

    if justOneRef then
        return num
    end

    --这里改为获取所有钻石的数量之和
    serData = itemList[ModelItem.ITEM_PAY_DIAMOND]
    if serData then
        num = num + (tonumber(serData:GetNum()) or 0)
    end

    return num
end

