function ModelItem:GetItemListByType(type)
    local list = self:GetItemList()
    local itemList = {}
    for i, v in pairs(list) do
        local ref = self:GetRefByRefId(v._refId)
        if ref and ref.display == 1 then
            local tabType = ref.tabType
            if (tabType and tabType > 0 and (tabType == type or type == ModelItem.Item_GENERAL)) then
                local data = {
                    itemType = 1,
                    itemId = v._refId,
                    itemNum = v._num,
                    sort = ref.order
                }
                table.insert(itemList, data)
            end
        end
    end
    table.sort(itemList, function(a, b)
        return a.sort < b.sort
    end)
    return itemList
end

function ModelItem:GetItemTypeListByType_Convert(itype)
    local list = self:GetItemList()
    local itemList = {}
    for i, v in pairs(list) do
        local ref = self:GetRefByRefId(v._refId)
        local tempType = self:GetType(v:GetRefId())
        if itype == tempType then
            local data = {
                itemType = 1,
                itemId = v._refId,
                itemNum = v._num,
                sort = ref.order
            }
            table.insert(itemList, data)
        end
    end
    table.sort(itemList, function(a, b)
        return a.sort < b.sort
    end)
    return itemList
end



function ModelItem:GetItemTypeListByType(itype)
    local list = self:GetItemList()
