function ModelItem:GetItemTypeListByTypeList(typeList)
    if not typeList then
        return {}
    end
    local typeKeyList = {}
    for i, v in ipairs(typeList) do
        typeKeyList[v] = v
    end
    local itemList = {}
    local tempType
    local list = self:GetItemList()
    for i, v in pairs(list) do
        tempType = self:GetType(v:GetRefId())
        if typeKeyList[tempType] then
            table.insert(itemList, v)
        end
    end
    return itemList
end

-- return tab or {}
function ModelItem:GetBtnType(refId, extra, fromBag)
    local ref = self:GetRefByRefId(refId)
    if not ref then return {} end

    local isSummon = false
    local isTimeEnd = false
    local refType = ref.type
    if refType == ModelItem.Item_Summon then
        if extra then
            local rankValue = extra.rankValue
            local endTime = extra.endTime
            if not string.isempty(endTime) and rankValue > 0 then
                isSummon = true
            end
            if not string.isempty(endTime) then
                local time = GetTimestamp()
                if time > tonumber(endTime) / 1000 then
                    isTimeEnd = true
                end
            end
        end
    end

    local isOpenSkin = true
    if refType == gModelItem.Item_SKINITEM and not gModelHeroExtra:CheckIsOpenSkin() then
        isOpenSkin = false
    end

    local retBtnList = {}
    local btnList = ref.btn
    if not string.isempty(btnList) then
        local btnarry = string.split(btnList, ",")
        for k, v in ipairs(btnarry) do
            v = tonumber(v)
            local isIns = true
            if not isOpenSkin then
                isIns = v ~= 1016
            end
            if isIns then
                local data = self:GetBtnInfo(v)
                if refType == ModelItem.Item_Summon then
                    if isSummon and isTimeEnd and data.btnId == 1026 then
                        data = nil
                    elseif isSummon and data.btnId == 1025 then
                        data = nil
                    elseif not isSummon and (data.btnId == 1026 or data.btnId == 1027) then
                        data = nil
                    end
                    if data then
                        table.insert(retBtnList, data)
                    end
                elseif refType == ModelItem.TTEM_TYPE_SORCERY_CARD then
                    local cardId = tonumber(string.sub(refId, -3))
                    local cardInfo = gModelSorceryCard:GetCardInfoByRefId(cardId)
                    local cfg = gModelSorceryCard:GetSorceryCardRefByRefId(cardId)
                    if cardInfo then
                        if cardInfo.level < cfg.sellLimitLevel and data.btnId == 1032 then
                            data = nil
                        end
                    else
                        if data.btnId == 1032 then
                            data = nil
                        end
                    end
                    if data then
                        table.insert(retBtnList, data)
                    end
                else
                    if data then
                        table.insert(retBtnList, data)
                    end
                end
            end
        end
    end

    if refType == gModelItem.TTEM_TYPE_DRACONIC then
        local starNum, draconicRefId = gModelDraconic:GetSpeechStarByItemId(refId)
        local isMax = gModelDraconic:IsStarMaxByItemRefId(refId)
        local data = {
            btnId = 0,
            name = "",
            icon = "public_btn_1_2",
            isclose = 0,
            tips = ""
        }

        -- 预览
        local data2 = {
            btnId = 0,
            name = ccClientText(41061),
            icon = "public_btn_1_1",
            isclose = 0,
            tips = "",
            func = function()
                GF.OpenWnd("UIDraconicUpStar", { refId = draconicRefId, tips = true, maxPre = true })
                return false
            end
        }

        if isMax then
            retBtnList = {}
            data.name = ccClientText(41064)
            data.icon = "public_btn_ash_1"
            data.func = function()
                GF.ShowMessage(ccClientText(41064))
                return false
            end
        else
            if starNum == -1 then
                data.name = ccClientText(41062)
            else
                data.name = ccClientText(41063)
            end

            data.func = function()
                if not gModelDraconic:CanActiveOrUpStar(draconicRefId, true) then
                    return false
                end
                GF.OpenWnd("UIDraconicUpStar", { refId = draconicRefId })
                return true
            end
            table.insert(retBtnList, data2)
        end
        table.insert(retBtnList, data)
        if not fromBag then
            retBtnList = {}
            table.insert(retBtnList, data2)
        end
    end

    return retBtnList
end

function ModelItem:GetBtnInfo(originId)
