function ModelItem:GetAppointCode(codeList)
    local retBtnList = {}
    if codeList == nil then
        return retBtnList
    end
    if type(codeList) == "string" then
        codeList = string.split(codeList, ",")
    end
    for i, v in ipairs(codeList) do
        local origin = GameTable.SourceConfigRef[tonumber(v)]
        if origin then
            local irefId = origin.refId
            local name = ccLngText(origin.name)
            local icon = origin.btnIcon
            local code = origin.code
            local isclose = origin.closeAll
            local tips = origin.tip
            table.insert(retBtnList, { btnId = irefId, name = name, icon = icon, code = code, isclose = isclose, tips = tips })
        end
    end
    return retBtnList
end

function ModelItem:GetWndNameByType(itype, refId, code, extraList, id, itemdata)
    if not itype then
        printInfoN("------- 没有填写类型")
        return false
    end
    local itemRef = self:GetRefByRefId(refId)
    if not itemRef then
        LogError("表格没有:" .. refId)
        return true
    end
    local banPackid = itemRef.banPackid
    if banPackid and not string.isempty(banPackid) then
        local packageId = gModelActivity:GetPackageId()
        banPackid = string.split(banPackid,",")
        for i,v in ipairs(banPackid) do
            if checknumber(v) == packageId then
                GF.ShowMessage(ccLngText(itemRef.banTips))
                return false
            end
        end
    end
    if code == ModelItem.BTNCODE_MAINCITY_USE then
        local info = {}
        table.insert(info, { refId = refId, num = 1, params = id })
        self:OnItemUseReq(info)
        return true
    end
    if code == ModelItem.BTNCODE_MAINCITY_SELL then
        local bSuc = false
        if itemRef then
            local skinId = checknumber(itemRef.typeDate)
            if skinId and skinId > 0 then
                local skinRef = GameTable.CastleSkinRef[skinId]
                if skinRef then
                    bSuc = true
                    local num = self:GetNumByRefId(refId)
                    local sell = LxDataHelper.ParseItem_3(itemRef.sell)
                    local sellNum = sell.itemNum * num
                    local sellName = gModelItem:GetNameByRefId(sell.itemId)
                    sellName = sellNum .. sellName
                    gModelGeneral:OpenUIOrdinTips({
                        refId = 10010,
                        para = {ccLngText(skinRef.name),sellName},
                        func = function ()
                            gModelGeneral:OnSellGoodsReq({
                                {itype = LItemTypeConst.TYPE_ITEM,refId = refId,num = num}
                            })
                        end
                    }, true)
                end
            end
        end
        return bSuc
    end
    if code == ModelItem.BTNCODE_HALIDOM_PRE or code == ModelItem.BTNCODE_HALIDOM_USE or
            code == ModelItem.BTNCODE_HALIDOM_COMPOUND or code == ModelItem.BTNCODE_HALIDOM_PRENOTOPT then
        local state = gModelHalidom:DisposeItemCode(code, refId)
        return state
    end
    if code == 1017 then
        --GF.OpenWndUp("UISpSye",{refId = refId})
        GF.OpenWndUp("UISyeProp", { refId = refId, defaultNum = 1 })
        return true
    end
    if code == 1016 then
        -- 皮肤预览
        gModelGeneral:RunOriginConfigCode(code, { refId = refId })
        return true
    end
    if code == 1015 then
        -- 皮肤专用
        gModelGeneral:RunOriginConfigCode(code, { refId = refId })
        return false
    end
    if (code == 1014) then
        --if(gModelFunctionOpen:CheckIsOpened(itemRef.useJump,true))then
        gModelFunctionOpen:Jump(itemRef.useJump, nil, nil, { itemId = refId })
        --end
        return true
    end
    if (code == 1013) then
        GF.OpenWndBottom("UIHuiYPay", { page = 2 })
        return true
    end
    if code == 1001 then
        gModelGeneral:RunOriginConfigCode(code, { refId = refId })
        GF.CloseWndByName("UIInip")
        return false
    end
    if code == 1012 then
        gModelGeneral:RunOriginConfigCode(code, { refId = refId })
        GF.CloseWndByName("UIInip")
        return false
    end
    if code == 1008 then
        gModelGeneral:RunOriginConfigCode(code, { refId = refId, itype = 1, id = id })
        GF.CloseWndByName("UIInip")
        return false
    end
    if code == 1022 then
        gModelGeneral:RunOriginConfigCode(code, { refId = refId, itype = 1 })
        GF.CloseWndByName("UIInip")
        return false
    end
    if code == 1018 then
        local status = false
        local id = extraList.id
        local isLeiDeng = self:GetLeiDengItemByRefId(refId)
        if isLeiDeng then
            status = self:CheckLeiDengIsGet(refId, id)
            if not status then
                local day = self:GetLeiDengCanGetNextDay(refId, id)
                local str
                if itype == ModelItem.Item_LEIDENGITEM then
                    str = string.replace(ccClientText(10237), LUtil.GetNDayTimeStr(nil, day))
                elseif itype == ModelItem.Item_DENGJILJITEM then
                    str = string.replace(ccClientText(10172), day)
                end
                if str then
                    GF.ShowMessage(str)
                end
            end
        else
            status = true
        end
        if status then
            local info = {}
            table.insert(info, { refId = refId, num = 1, params = id })
            self:OnItemUseReq(info)
        end
        return false
    end
    if code == 1019 then
        --- 道具弹窗：梦境之旅道具的【使用】按钮，点击弹出梦境之旅道具的使用弹窗，不存在 道具，删除
    end
    if code == 1024 then
        gModelGeneral:RunOriginConfigCode(code, { refId = refId, itype = 1 })
        GF.CloseWndByName("UIInip")
        return false
    end
    if code == 1025 or code == 1026 or code == 1027 then
        gModelGeneral:RunOriginConfigCode(code, { refId = refId, itype = 1, id = id })
        GF.CloseWndByName("UIInip")
        return false
    end
    if code == 1011 then
        gModelGeneral:RunOriginConfigCode(code, { typeDate = itemRef.typeDate })
        return true
    end
    if code == 1029 then
        gModelGeneral:RunOriginConfigCode(code, { typeDate = itemRef.typeDate })
        return true
    end

    if code == 1004 and itemRef.type == ModelItem.ITEM_THOUSAND then
        GF.OpenWnd("UIHunottery", { itemdata = itemdata })
        return true
    end

    if code == 1032 then
        if itype == ModelItem.TTEM_TYPE_SORCERY_CARD then
            GF.OpenWnd("UISorceryCardSell")
            return true
        end
        gModelGeneral:RunOriginConfigCode(code,{refId = refId, itype = 1, id = id})
        return true
    end
    if code == 1033 then
        local petId = GameTable.PlayerItemRef[itemdata.refId].typeDate
        petId = tonumber(petId)
        GF.OpenWnd("UIPeView",{refId = petId,isPreview = true, playerId = gLGameLogin:GetPlayerId()})
        return false
    end

    if code == 1034 then
        gModelGeneral:RunOriginConfigCode(code, { typeDate = itemRef.typeDate })
        return false
    end
    if code == 1036 then
        -- gModelGeneral:RunOriginConfigCode(code, { typeDate = itemRef.typeDate })
        gModelFunctionOpen:Jump(36000000)
        local origin = GameTable.SourceConfigRef[code]
        return origin.closeAll
    end

    local canUseMore = itemRef.canUseMore
    local maxValue = self:GetNumByRefId(refId)
    local defaultNum = itemRef.defaultNum
    if canUseMore == 0 then
        if itype == ModelItem.Item_GIFT then
            local info = {}
            table.insert(info, { refId = refId, num = 1 })
            self:OnItemUseReq(info)
        elseif itype == ModelItem.Item_CHOOSE or itype == ModelItem.Item_SELECT_TRY_HERO or itype == ModelItem.Item_SELECT_TRY_SPIRITHERO then
            GF.OpenWndUp("UIGetTip", { refId = refId, itemType = 1 })
        elseif itype == ModelItem.Item_STARPASS or itype == ModelItem.Item_LVPASS then
            GF.OpenWndUp("UIGetTip", { refId = refId, itemType = 2 })
        elseif itype == ModelItem.TTEM_TYPE_SORCERY_CARD then
            if code == 1035 then
                local idS = tostring(refId)
                local refIdS = string.sub(idS, -3)
                GF.OpenWnd("UISorceryCardUpLv", { refId = tonumber(refIdS) })
                return true
            end
        end
    elseif canUseMore == 1 then
        -- 镜魂需要判断是否是一份的量，如果一份量直接使用，多余一份调用批量使用窗口
        --if itype == ModelItem.Item_DEBRIS or itype == ModelItem.DEBRIS_COMPOUND then
        local showUISyeProp = false
        if self:CheckIsDebrisByIType(itype) then
            local typeData = itemRef.typeDate
            if itype == ModelItem.Item_DEBRIS then
                local heroBagNum, heroNum = gModelHero:GetHoerBagNum(), gModelHero:GetHeroNum()
                if heroNum >= heroBagNum then
                    GF.ShowMessage(ccClientText(10060))
                    return false
                end
                -- 【C宠物系统】删掉宠物系统相关
                -- elseif itype == ModelItem.ITEM_PET_DEBRIS then
                -- 	local petBagLimit = gModelPetSpace:GetPetBagLimit()
                -- 	local curPetBagNum  =gModelPetSpace:GetCurPetBagNum()
                -- 	if curPetBagNum >= petBagLimit then
                -- 		--gModelGeneral:OpenUIOrdinTips({refId = 380002,func = function()
                -- 		--end})
                -- 		gModelGeneral:OpenUIOrdinTips({refId = 380010,func = function()
                -- 			GF.OpenWnd("WndPetBag")
                -- 		end})
                -- 		return false
                -- 	else
                -- 		showUISyeProp = maxValue>petBagLimit-curPetBagNum
                -- 		maxValue = maxValue>petBagLimit-curPetBagNum and petBagLimit-curPetBagNum or maxValue
                -- 	end
            end
            if itype == ModelItem.TTEM_TYPE_SORCERY then
                if code == 1035 then
                    local idS = tostring(refId)
                    local refIdS = string.sub(idS, -3)
                    GF.OpenWnd("UISorceryCardUpLv", { refId = tonumber(refIdS) })
                    return true
                end
            end
            if not string.isempty(typeData) then
                self:DOItemUseReq(typeData, maxValue, refId, itype, defaultNum, showUISyeProp)
                return true
            end
        else
            if maxValue == 1 then
                local info = {}
                table.insert(info, { refId = refId, num = maxValue })
                self:OnItemUseReq(info)
            else
                local tab = {
                    refId = refId,
                    maxValue = maxValue,
                    itype = itype,
                    defaultNum = defaultNum,
                    func = function()
                        gModelGeneral:OpenItemInfoTip(refId)
                    end
                }
                GF.OpenWndUp("UISyeProp", tab)
            end
        end
    end
    return true
end

function ModelItem:DOItemUseReq(typeData, maxValue, refId, itype, defaultNum, showUISyeProp)
    local typeList = string.split(typeData, ",")
    for i, v in ipairs(typeList) do
        local strList = string.split(v, "=")
        local num = tonumber(strList[3])
        if num > maxValue then
            GF.ShowMessage(ccClientText(10226))
            return false
        elseif maxValue / num < 2 and not showUISyeProp then
            local info = {}
            table.insert(info, { refId = refId, num = num })
            self:OnItemUseReq(info)
        else
            local tab = {
                refId = refId,
                maxValue = maxValue,
                itype = itype,
                defaultNum = defaultNum,
                func = function()
                    gModelGeneral:OpenItemInfoTip(refId)
                end
            }
            GF.OpenWndUp("UISyeProp", tab)
        end
    end
end

function ModelItem:GetTypeDataByRefId(refId)
    local ref = self:GetRefByRefId(refId)
    local retList = {}
    if ref then
        local refType = ref.type
        local typeData = ref.typeDate
        if not string.isempty(typeData) then
            local delimiter = ','
            if refType == ModelItem.Item_SELECT_TRY_HERO or refType == ModelItem.Item_SELECT_TRY_SPIRITHERO then
                delimiter = '|'
            end

            local typeList = string.split(typeData, delimiter)
            for i, v in ipairs(typeList) do
                local strList = string.split(v, "=")
                --if refType == ModelItem.Item_DEBRIS or refType == ModelItem.Item_STARPASS or refType == ModelItem.Item_LVPASS or refType == ModelItem.DEBRIS_COMPOUND then
                if self:CheckIsDebrisByIType(refType) or refType == ModelItem.Item_STARPASS or refType == ModelItem.Item_LVPASS then
                    retList[i] = { isRandom = tonumber(strList[1]), refId = tonumber(strList[2]), num = tonumber(strList
                    [3]) }
                elseif refType == ModelItem.Item_GIFT or refType == ModelItem.Item_CHOOSE then
                    retList[i] = { itype = tonumber(strList[1]), refId = tonumber(strList[2]), num = tonumber(strList[3]) }
                elseif refType == ModelItem.Item_MIRRORSOUL then
                    retList[i] = { isRandom = tonumber(strList[1]), star = tonumber(strList[2]) }
                elseif refType == ModelItem.Item_SELECT_TRY_HERO or refType == ModelItem.Item_SELECT_TRY_SPIRITHERO then
                    local heroOnlyShowData = gModelHero:GetTryHeroOnlyShowData(tonumber(strList[1]), refType)
                    retList[i] = { itype = LItemTypeConst.TYPE_HERO, refId = tonumber(strList[1]), num = 1, heroOnlyShowData = heroOnlyShowData }
                else
                    retList[i] = { refId = strList[1], num = tonumber(strList[2]) }
                end
            end
        end
    end
    return retList
end

