function ModelItem:GetHeroColorByQuality(starLv, returnqua)
    local quality = 0
    for k = 1, 7 do
        local v = self._qualityList[k]
        if v then
            if starLv <= v and quality <= k then
                quality = k
                break
            end
        end
    end
    if returnqua and quality ~= 0 then
        return quality
    end
    if quality ~= 0 then
        return self:GetColorStringByQualityId(quality)
    end
end

