function ModelItem:ParseJump(str)
    local tempList = string.split(str, ',')
    local t = {}
    for k, v in ipairs(tempList) do
        local s, e, cap1, cap2 = string.find(v, "(%d+)=(%d+)")
        if cap1 and cap2 then
            local data = {
                jumpId = tonumber(cap1),
                textId = tonumber(cap2)
            }
            table.insert(t, data)
        end
    end
    return t
end

