        self._equipStrengthItemList_1 = {}
    end

    if not self._equipStrengthItemList_2 then
        self._equipStrengthItemList_2 = {}
    end

    local itype, refId, typeDate
    for i, v in pairs(GameTable.PlayerItemRef) do
        itype = v.type
        refId = v.refId
        typeDate = v.typeDate

        --[[		if itype == ModelItem.Item_DEBRIS or itype == ModelItem.DEBRIS_COMPOUND then]]
        if self:CheckIsDebrisByIType(itype) then
            --- 英雄镜魂
            typeDate = string.split(typeDate, "=")
            if itype == ModelItem.Item_DEBRIS or itype == ModelItem.TTEM_TYPE_EQUIP_STRENGTH_3 or itype == ModelItem.TTEM_TYPE_SORCERY then
                self._suiPianList[refId] = tonumber(typeDate[3])
            elseif itype == ModelItem.DEBRIS_COMPOUND then
                self._debrisCompoundList[refId] = tonumber(typeDate[3])
                -- 【C宠物系统】删掉宠物系统相关
                -- elseif itype == ModelItem.ITEM_PET_DEBRIS then
                -- 	self._petDebrisList[refId] = tonumber(typeDate[3])
                
    
            end
        elseif itype == ModelItem.Item_MIRRORSOUL then
            --- 英魂道具
            typeDate = string.split(typeDate, "=")
            self._yinghunList[refId] = { race = tonumber(typeDate[1]), star = tonumber(typeDate[2]) }
        elseif itype == ModelItem.Item_GENERAL then
            --- 常规道具
            if typeDate == "1" then
                self._runeItemList[refId] = refId
            end
            -- elseif itype == ModelItem.Item_UPOUTFIT then
            -- 	--- 装备经验道具
            -- 	self._upOutfitList[refId] = tonumber(typeDate)
            -- elseif itype == ModelItem.Item_UPOUTFITRECAST then
            -- 	--- 重铸道具
            -- 	typeDate = string.split(typeDate,"=")
            -- 	local tempList = {}
            -- 	local tempKeyList = {}
            -- 	local outfitSelType = tonumber(typeDate[1])
            -- 	local rangList = string.split(typeDate[2],",")
            -- 	for idx,val in ipairs(rangList) do
            -- 		local temp = tonumber(val)
            -- 		table.insert(tempList,temp)
            -- 		tempKeyList[temp] = temp
            -- 		if outfitSelType == 3 then
            -- 			local upOutfitHeroMaterialsInfo = self._upOutfitHeroMaterialsList[temp]
            -- 			if not upOutfitHeroMaterialsInfo then
            -- 				upOutfitHeroMaterialsInfo = {}
            -- 				self._upOutfitHeroMaterialsList[temp] = upOutfitHeroMaterialsInfo
            -- 			end
            -- 			table.insert(upOutfitHeroMaterialsInfo,refId)
            -- 		end
            -- 	end
            -- 	self._upOutfitMaterialsList[refId] = {
            -- 		itemType = outfitSelType,rangList = tempList,rangKeyList = tempKeyList,
            -- 	}
        elseif itype == ModelItem.TTEM_TYPE_BADGE or itype == ModelItem.TTEM_TYPE_BADGE_1 then
            self._badgeItemList[refId] = {refId=refId,quality = v.quality}
        elseif itype == ModelItem.Item_LEIDENGITEM or itype == ModelItem.Item_DENGJILJITEM then
            --- 累登道具、等级道具
            local t = {}
            typeDate = string.split(typeDate, "|")
            for idx, val in ipairs(typeDate) do
                val = string.split(val, ":")
                local rewardList = {}
                local day = tonumber(val[1])
                local reward = string.split(val[2], ",")
                for _i, rewardInfo in ipairs(reward) do
                    rewardInfo = string.split(rewardInfo, "=")
                    table.insert(rewardList, {
                        itemId = tonumber(rewardInfo[2]),
                        itemType = tonumber(rewardInfo[1]),
                        itemNum = tonumber(rewardInfo[3]),
                    })
                end
                table.insert(t, {
                    day = day,
                    rewardList = rewardList,
                })
            end
            self._leidengItemList[refId] = t
        elseif itype == ModelItem.Item_RUNESEL then
            --- 自选符文道具
            local typeDataList = string.split(typeDate, "=")
            local runeRefId = tonumber(typeDataList[1])
            local attrGroupList = string.split(typeDataList[2], ",")
            local skillGroupList = string.split(typeDataList[3], ",")
            local tAttrGroupList = {}
            for _i, _v in ipairs(attrGroupList) do
                table.insert(tAttrGroupList, tonumber(_v))
            end
            local tSkillGroupList = {}
            for _i, _v in ipairs(skillGroupList) do
                table.insert(tSkillGroupList, tonumber(_v))
            end
            self._runeSelItemList[refId] = {
                runeRefId = runeRefId,
                attrGroup = tAttrGroupList,
                skillGroup = tSkillGroupList,
            }
            -- elseif itype == ModelItem.Item_TREASURESKIN then
            -- 	--- 宝物皮肤道具
            -- 	self._treasureSkinList[i] = i
        elseif itype == ModelItem.Item_RUNEUSEITEM then
            --- 符文镜魂道具
            self._runeUseItemList[i] = {
                itemType = LItemTypeConst.TYPE_ITEM,
                runeRefId = tonumber(typeDate),
            }
        elseif itype == ModelItem.Item_TIMEHOURGLASS then
            --- 道具-时光沙漏专用
            typeDate = string.split(typeDate, "=")
            self._timeHourGlassList[i] = {
                heroStar = tonumber(typeDate[1]),
                returnToStar = tonumber(typeDate[2]),
            }
        elseif itype == ModelItem.Item_SELECT_TRY_HERO or itype == ModelItem.Item_SELECT_TRY_SPIRITHERO then
            typeDate = string.split(typeDate, "|")
            local keyData = {}
            local listData = {}
            local heroRefId, useTime
            for idx, val in ipairs(typeDate) do
                val = string.split(val, "=")
                heroRefId, useTime = tonumber(val[1]), tonumber(val[2])
                keyData[heroRefId] = useTime
                table.insert(listData, {
                    heroRefId = heroRefId,
                    useTime = useTime,
                })
            end
            self._tryHeroTypeList[refId] = {
                keyData = keyData,
                listData = listData,
            }
        elseif itype == ModelItem.ITEM_GOLEM_EXP_TYPE then
            local data = {
                refId = refId,
                conversionExp = tonumber(typeDate) or 1,
                order = v.order
            }
            table.insert(self._golemExpItemList, data)
            self._golemExpItemKeyList[refId] = data
            -- 【C宠物系统】删掉宠物系统相关
            -- elseif itype == ModelItem.ITEM_PET_SOUL then --宠物英魂
            -- 	typeDate = string.split(typeDate,"=")
            -- 	self._petSoulList[refId] = {quality = tonumber(typeDate[1]),star = tonumber(typeDate[2])}

        elseif itype == ModelItem.TTEM_TYPE_EQUIP_STRENGTH_1 then
            refId = v.refId
            typeDate = v.typeDate
            typeDate = string.split(typeDate, "=")
            local addExp = typeDate[2]
            if nil ==addExp then
                addExp= typeDate[1]
            end

            local data = {}
            data.refId = refId
            data.addExp = addExp
            data.itemType =LItemTypeConst.TYPE_ITEM
            table.insert(self._equipStrengthItemList_1, data)
        elseif itype == ModelItem.TTEM_TYPE_EQUIP_STRENGTH_2 then
            refId = v.refId
            typeDate = v.typeDate
            typeDate = string.split(typeDate, "=")
            local addExp = typeDate[2]
            local data = {}
            data.refId = refId
            data.addExp = addExp
            data.itemType =LItemTypeConst.TYPE_ITEM
            table.insert(self._equipStrengthItemList_2, data)
        end
    end
    table.sort(self._golemExpItemList, function(a, b)
        return a.order < b.order
    end)
end

function ModelItem:InitItemRewardShowRef()
    local list = {}
    self._itemRewardShowList = list
    for k, v in pairs(GameTable.PlayerItemRewardShowRef) do
        local rewardList = list[k]
        if not rewardList then
            rewardList = {}
            list[k] = rewardList
        end
        local name = v.name
        local probability = v.probability
        local text = ""
        name = string.split(name, ",")
        probability = string.split(probability, ",")
        for index, val in ipairs(name) do
            val = string.split(val, "=")
            local prob = probability[index]
            table.insert(rewardList, { itype = tonumber(val[1]), refId = tonumber(val[2]), num = tonumber(val[3]),probability = prob})
        end

    end
end

function ModelItem:InitItemHeroFreeAttrRef()
    local list = {}
    self._itemHeroFreeAttrList = list
    for k, v in pairs(GameTable.PlayerItemHeroFreeAttrRef) do
        local hero = v.hero
        if not list[hero] then
            list[hero] = {}
        end

        local openDayList = string.split(v.openDay, '|')
        local matchStar = string.split(v.matchStar, '=')
        local data = {
            refId = v.refId,
            star = v.star,
            openDayStart = tonumber(openDayList[1]),
            openDayEnd = tonumber(openDayList[2]) or -1,
            targetHeroIndex = tonumber(matchStar[1]), --玩家所有英雄星级排序后的第几位，英雄数量不够匹配则取最后一个位置
            targetHeroStar = tonumber(matchStar[2]), --玩家所有英雄星级排序后的第几位应匹配的星级，无匹配则取最低配置星级
        }

        table.insert(list[hero], data)
    end
end

