function ModelItem:GetBagStatus(ignoreQuality, ignorePeizhi)
    local list = self:GetItemList()
    for k, v in pairs(list or {}) do
        local refId = v:GetRefId()

        if not ignorePeizhi then
            --检查是否为配制显示红点的道具
            if gModelItem:GetIsShowRedPointByRefId(refId) then
                return true
            end
        end

        local suipian = self:GetSuiPianNeedNumByRefId(refId)
        if suipian then
            local ref = self:GetRefByRefId(refId)
            if ref then
                local num = tonumber(v:GetNum())
                if ignoreQuality then
                    if num >= suipian then
                        return true
                    end
                else
                    local quality = ref.quality
                    if quality > 4 then
                        if num >= suipian then
                            return true
                        end
                    end
                end
            end
        end
    end
    local status = false
    if not ignorePeizhi then
        status = self:CheckAllLeiDengStatus()
    end
    return status
end

function ModelItem:CheckAllLeiDengStatus()
    local status = false
    for refId, leidengInfoList in pairs(self._bagExtraItemList) do
        if status then
            break
        end
        for id, leidengInfo in pairs(leidengInfoList) do
            if status then
                break
            end
            status = self:CheckLeiDengIsGet(refId, id)
        end
    end
    return status
end

function ModelItem:CheckLeiDengIsGet(refId, id)
    local bagExtraItemList = self._bagExtraItemList or {}
    local bagExtraItemRefIdList = bagExtraItemList[refId] or {}
    local LeiDengServerData = bagExtraItemRefIdList[id]
    if LeiDengServerData then
        local status = false
        local LeiDengInfo = self:GetLeiDengItemByRefId(refId)
        if not LeiDengInfo then
            return status
        end
        local itype = self:GetType(refId)
        if itype == ModelItem.Item_LEIDENGITEM then
            local createTime = LeiDengServerData.createTime / 1000
            local createZeroTime = LUtil.GetNextDayTimes(createTime)
            local curTime = GetTimestamp()
            local zeroTime = LUtil.GetNextDayTimes(curTime, 1)
            local lostDay = zeroTime - createZeroTime
            local changeDay = LUtil.GetCurTimeDayNum(lostDay)
            local rewardDaysKey = LeiDengServerData.rewardDaysKey or {}
            for i, v in ipairs(LeiDengInfo) do
                if status then
                    break
                end
                local day = v.day
                status = rewardDaysKey[day] == nil and day <= changeDay
            end
        elseif itype == ModelItem.Item_DENGJILJITEM then
            local playerLv = gModelPlayer:GetPlayerLv()
            local rewardDaysKey = LeiDengServerData.rewardDaysKey or {}
            for i, v in ipairs(LeiDengInfo) do
                if status then
                    break
                end
                local day = v.day
                status = rewardDaysKey[day] == nil and day <= playerLv
            end
        end
        return status
    end
    return false
end

function ModelItem:GetLeiDengCanGetNextDay(refId, id)
    local day = 0
    local bagExtraItemList = self._bagExtraItemList or {}
    local bagExtraItemRefIdList = bagExtraItemList[refId] or {}
    local LeiDengServerData = bagExtraItemRefIdList[id]
    if LeiDengServerData then
        local LeiDengInfo = self:GetLeiDengItemByRefId(refId)
        if not LeiDengInfo then
            return day
        end
        local itype = self:GetType(refId)
        if itype == ModelItem.Item_LEIDENGITEM then
            local createTime = LeiDengServerData.createTime / 1000
            local createZeroTime = LUtil.GetNextDayTimes(createTime)
            local curTime = GetTimestamp()
            local zeroTime = LUtil.GetNextDayTimes(curTime, 1)
            local lostDay = zeroTime - createZeroTime
            local changeDay = LUtil.GetCurTimeDayNum(lostDay)
            local rewardDaysKey = LeiDengServerData.rewardDaysKey or {}
            for i, v in ipairs(LeiDengInfo) do
                local tday = v.day
                if rewardDaysKey[tday] == nil then
                    day = tday - changeDay
                    break
                end
            end
        elseif itype == ModelItem.Item_DENGJILJITEM then
            local playerLv = gModelPlayer:GetPlayerLv()
            local rewardDaysKey = LeiDengServerData.rewardDaysKey or {}
            for i, v in ipairs(LeiDengInfo) do
                local tday = v.day
                if rewardDaysKey[tday] == nil then
                    day = tday
                    break
                end
            end
        end
    end
    return day
end

