function ModelItem:IsUpNeedEnough(items)
    --判断物品是否足够
    for k, v in ipairs(items) do
        local itemId = v.itemId
        local itemNum = v.itemNum
        local own = self:GetNumByRefId(itemId)
        if itemNum > tonumber(own) then
            return false, itemId
        end
    end
    return true
end

