function ModelItem:GetCurItemHeroFreeAttrRef(heroRefId)
    local dayPast = gLGameLogin:GetServerOpenDay()
    local dataList = self:GetItemHeroFreeAttrData(heroRefId)
    local openDayDataList = {}
    for k, v in ipairs(dataList) do
        local openDayStart = v.openDayStart
        local openDayEnd = v.openDayEnd
        if dayPast >= openDayStart and (openDayEnd < 0 or dayPast <= openDayEnd) then
            table.insert(openDayDataList, v)
        end
    end

    table.sort(openDayDataList, function(a, b)
        return a.star < b.star
    end)

    local starList = gModelHero:GetAllHeroStarList()
    local starListMaxNum = #starList
    if starListMaxNum == 0 then
        printInfoNR("no hero")
        return nil
    end

    local curRef
    for k, v in ipairs(openDayDataList) do
        local targetHeroIndex = v.targetHeroIndex
        local targetHeroStar = v.targetHeroStar
        local indexStar = starList[targetHeroIndex]
        if not indexStar then
            indexStar = starList[starListMaxNum]
        end

        if indexStar <= targetHeroStar then
            curRef = v
            break
        end
    end

    if not curRef then
        curRef = openDayDataList[1]
    end

    return curRef
end

function ModelItem:GetCompoundRuneItemList(quality)
    local itemList = self:GetItemList() or {}
    local runeUseItemList = self._runeUseItemList or {}
    local runeUseInfo
    local iRuneQuality
    local refId, num, runeRefId
    local list = {}
    for i, v in pairs(itemList) do
        refId = v:GetRefId()
        num = tonumber(v:GetNum())
        runeUseInfo = runeUseItemList[refId]
        if runeUseInfo and num > 0 then
            runeRefId = runeUseInfo.runeRefId
            iRuneQuality = gModelRune:GetRuneQualityByRefId(runeRefId)
            for idx = 1, num do
                if quality then
                    if quality == iRuneQuality then
                        table.insert(list, {
                            itemType = v:GetType(),
                            refId = refId,
                            num = 1,
                            runeRefId = runeRefId,
                            id = refId .. "_" .. idx,
                            index = idx,
                        })
                    end
                else
                    table.insert(list, {
                        itemType = v:GetType(),
                        refId = refId,
                        num = 1,
                        runeRefId = runeRefId,
                        id = refId .. "_" .. idx,
                        index = idx,
                    })
                end
            end
        end
    end
    return list
end

function ModelItem:GetRuneUseItemList(needRuneRefId)
    local runeItemList = {}
    local itemList = self:GetItemList() or {}
    local runeUseItemList = self._runeUseItemList or {}
    local runeUseInfo
    local refId
    for i, v in pairs(itemList) do
        refId = v:GetRefId()
        runeUseInfo = runeUseItemList[refId]
        if runeUseInfo and runeUseInfo.runeRefId == needRuneRefId and tonumber(v:GetNum()) > 0 then
            table.insert(runeItemList, v:GetServerData())
        end
    end
    return runeItemList
end

function ModelItem:GetUseRuneItemRuneRefId(refId)
    local runeUseItemList = self._runeUseItemList or {}
    local runeUseItemInfo = runeUseItemList[refId]
    return runeUseItemInfo and runeUseItemInfo.runeRefId
end

