function ModelItem:FormatItemListStr(str)
    local items = LxDataHelper.ParseItem_3List(str)
    local strList = {}
    for k, v in ipairs(items) do
        local temp = gModelGeneral:GetCommonItemColorName(v, "*")
        table.insert(strList, temp)
