    return table.concat(strList, ',')
end

function ModelItem:GetSkinRefIdByItemId(refId)
    local itemRef = self:GetRefByRefId(refId)
    if not itemRef then
        LogError("no item ref " .. tostring(refId))
        return
    end
    if itemRef.type ~= ModelItem.Item_SKINITEM then
        return
    end

    local strs = string.split(itemRef.typeDate, '=')
    if #strs < 1 then
        printErrorN(string.format("typedate is wrong itemRefId %s", refId))
        return
    end
    local skinRefId = tonumber(strs[1])
    return skinRefId
end

function ModelItem:CheckIsDebrisByRefId(refId)
    if not refId then
        return false
    end
    local iType = self:GetType(refId)
    return self:CheckIsDebrisByIType(iType)
end

function ModelItem:CheckIsDebrisByIType(itype)
