end

function ModelItem:IsSkinItem(itemdata)
    if itemdata.itemType ~= LItemTypeConst.TYPE_ITEM then
        return false
    end
    local itemId = itemdata.itemId
    local itemRef = self:GetRefByRefId(itemId)
    return itemRef.type == ModelItem.Item_SKINITEM
end

