function ModelItem:BagAutoCompFunc(srcWnd)
    local sendMsgFunc = function(sendList)
        self:OnItemUseReq(sendList)
    end
    local compItemList = {}
    local list1 = self:GetItemTypeListByType(ModelItem.DEBRIS_COMPOUND)
    local list2 = self:GetItemTypeListByType(ModelItem.TTEM_TYPE_SORCERY)
    local compoundItemList = {}
    for _, v in ipairs(list1) do
        table.insert(compoundItemList, v)
    end
    for _, v in ipairs(list2) do
        table.insert(compoundItemList, v)
    end
    local refId, num, needNum, tNum, compNum
    local recordCompoundItemList = {}
    for i, v in ipairs(compoundItemList) do
        refId = v:GetRefId()
        num = tonumber(v:GetNum())
        needNum = self:GetSuiPianNeedNumByRefId(refId)
        if needNum and num >= needNum then
            tNum = math.floor(num / needNum)
            compNum = tNum * needNum
            local data = {
                itemType = LItemTypeConst.TYPE_ITEM,
                refId = refId,
                num = compNum,
                itemNum = compNum,
            }
            table.insert(compItemList, data)
            table.insert(recordCompoundItemList, data)
        end
    end
    local compItemLen = #compItemList
    local status = compItemLen < 1

    --todo 宠物碎片 145

    local isFull = gModelGeneral:IsFullHeroBag(nil, nil, nil, true, 53004, srcWnd, not status)
    if isFull then
        if not status then
            local dicOpenParam = {}
            dicOpenParam.itemList = compItemList
            gModelGeneral:ShowUIOrdinTipLazy(10017, function()
                sendMsgFunc(compItemList)
            end, dicOpenParam)
        end
        return
    else
        local heroItemList = self:GetItemTypeListByType(ModelItem.Item_DEBRIS)
        if #heroItemList > 0 then
            local compHeroList = {}
            for i, v in ipairs(heroItemList) do
                refId = v:GetRefId()
                num = tonumber(v:GetNum())
                needNum = self:GetSuiPianNeedNumByRefId(refId)
                if needNum and num >= needNum then
                    tNum = math.floor(num / needNum)
                    compNum = tNum * needNum
                    local randType, heroRefId, oCcompNum = self:CheckItemDebrisNum(refId)
                    local data = {
                        itemType = LItemTypeConst.TYPE_ITEM,
                        refId = refId,
                        num = compNum,
                        itemNum = compNum,
                        randType = randType,
                        heroRefId = heroRefId,
                        compNum = oCcompNum,
                    }
                    table.insert(compHeroList, data)
                end
            end
            if #compHeroList > 0 then
                for i, v in ipairs(compHeroList) do
                    table.insert(compItemList, {
                        itemType = v.itemType,
                        refId = v.refId,
                        num = v.num,
                        itemNum = v.itemNum,
                    })
                end
                table.sort(compHeroList, function(a, b)
                    local refIdA, refIdB = a.refId, b.refId
                    local randTypeA, heroRefIdA = a.randType, a.heroRefId
                    local randTypeB, heroRefIdB = b.randType, b.heroRefId
                    local refA = self:GetRefByRefId(refIdA)
                    local refB = self:GetRefByRefId(refIdB)
                    if randTypeA == randTypeB and randTypeA == 1 then
                        local qualityA, qualityB = refA.quality, refB.quality
                        if qualityA == qualityB then
                            local raceA, raceB = gModelHero:GetHeroType(heroRefIdA), gModelHero:GetHeroType(heroRefIdB)
                            if not raceA then
                                raceA = 1
                                if LOG_INFO_ENABLED then
                                    LogError("not raceA = " .. heroRefIdA)
                                end
                            end
                            if not raceB then
                                raceB = 1
                                if LOG_INFO_ENABLED then
                                    LogError("not raceB = " .. heroRefIdB)
                                end
                            end
                            if raceA == raceB then
                                return heroRefIdA > heroRefIdB
                            else
                                return raceA > raceB
                            end
                        else
                            return qualityA > qualityB
                        end
                    elseif randTypeA == randTypeB and randTypeA == 2 then
                        -- 道具排序
                        local qualityA, qualityB = refA.quality, refB.quality
                        if qualityA == qualityB then
                            return refA.order > refB.order
                        else
                            return qualityA > qualityB
                        end
                    else
                        return randTypeA > randTypeB
                    end
                end)
                local func = function()
                    sendMsgFunc(compItemList)
                end
                local tItemList = {}
                if #recordCompoundItemList > 0 then
                    for i, v in ipairs(recordCompoundItemList) do
                        table.insert(tItemList, v)
                    end
                end
                for i, v in ipairs(compHeroList) do
                    table.insert(tItemList, v)
                end
                local dicOpenParam = {}
                dicOpenParam.itemList = tItemList
                gModelGeneral:ShowUIOrdinTipLazy(10017, func, dicOpenParam)
                return
            else
                if not status then
                    sendMsgFunc(compItemList)
                    return
                end
            end
        else
            if not status then
                sendMsgFunc(compItemList)
                return
            end
        end
    end
    GF.ShowMessage(ccClientText(10242)) -- 无可合成碎片
end

---千抽道具 召唤接口
function ModelItem:FormatItemUniqueData(refId, id)
    local itemData = self:GetItemServerDataByRefId(refId)
    if not itemData then
        return
    end

    local extraData = itemData:GetExtraData(id)
    if not extraData then
        return
    end

    local data = {
        refId = refId,
        num = 1,
        id = id,
        extra = JSON.decode(extraData.extra)
    }

    printInfoN("extra " .. extraData.extra)
    return data
end

function ModelItem:GetCallNumLeft(refId, id, round)
    local roundData = self:GetRoundData(refId, id, round)
    if not roundData then
        return 0
    end

    local cnt = #roundData.recordList
    return 10 - cnt
end

function ModelItem:GetRoundData(refId, id, round)
    local itemData = self:GetItemServerDataByRefId(refId)
    if not itemData then
        return
    end

    local extraData = itemData:GetExtraData(id)
    if not extraData then
        return
    end
    local extra = JSON.decode(extraData.extra)
    if not extra then
        return
    end

    local roundData = extra.roundList[round]
    return roundData
end

function ModelItem:GetUnselectRecord(refId, id, round)
    local roundData = self:GetRoundData(refId, id, round)
    if not roundData then
        return
    end

    for k, v in ipairs(roundData.recordList) do
        if v.select == ModelItem.SELECT_STATE_INIT then
            return v
        end
    end
end

function ModelItem:CheckShowUnSave(refId, id, round)
    local unsaveRecord = self:GetUnselectRecord(refId, id, round)
    if not unsaveRecord then
        return
    end
    local itemdata = self:FormatItemUniqueData(refId, id)
    local para = {
        refId = 470403,
        func = function()
            local wndpara = {
                result = unsaveRecord,
                isNoEff = true,
                itemdata = itemdata,
                round = round,
                wndType = 2,
            }
            GF.OpenWnd("UILotteryRltsPop", wndpara)
        end
    }
    gModelGeneral:OpenUIOrdinTips(para)
    return true
end

function ModelItem:OnClickSummon(refId, id, round)
    if self:CheckShowUnSave(refId, id, round) then
        return
    end

    local leftCnt = self:GetCallNumLeft(refId, id, round)
    if leftCnt <= 0 then
        local str = ccClientText(21013) --"次数不足！")
        GF.ShowMessage(str)
        return
    end

    local para = {
        round = round,
        id = id
    }

    gModelItem:ItemUseThousandCall(refId, 1, para)

    return true
end

function ModelItem:ShareCallResult(para)
    local result = para.result
    local root = para.root
    local playerName = gModelPlayer:GetPlayerName()
    local rewards = LxDataHelper.ParseItem(result.reward)
    local list = {}
    for k, v in ipairs(rewards) do
        local data = {
            count = v.itemNum,
            effect = v.isShowEff,
            itemId = v.itemId,
            type = v.itemType
        }
        table.insert(list, data)
    end

    local data = {
        extraReward = list,
        createTime = result.createTime,
        rankValue = result.rankValue,
        callPlayerName = playerName,
        shareType = ModelChat.CHAT_SHARE_33
    }

    local jsonStr = JSON.encode(data)
    local data = {
        root = root,
        shareType = ModelChat.CHAT_SHARE_33,
        shareData = jsonStr
    }
    gModelGeneral:OpenShareTip(data)
end

--- 道具 转 圣物
function ModelItem:GetItem2HalidomCompoundInfo(refId)
    local ref = self:GetRefByRefId(refId)
    if not ref then
        return
    end

    if ref.type ~= ModelItem.TTEM_TYPE_HALIDOMITEM then
        return
    end

    if not self._item2HalidomCompoundInfoMap then
        self._item2HalidomCompoundInfoMap = {}
    end
    local data = self._item2HalidomCompoundInfoMap[refId]
    if not data then
        local typeDate = string.split(ref.typeDate, "=")
        data = {
            --- 圣物 refId
            halidomRefId = tonumber(typeDate[1]),
            --- 合成数量
            compoundNum = tonumber(typeDate[2]),
        }
        self._item2HalidomCompoundInfoMap[refId] = data
    end
    return data
end

function ModelItem:GetItem2HalidomRefId(refId)
    local halidomInfo = self:GetItem2HalidomCompoundInfo(refId)
    if not halidomInfo then
        return
    end
    return halidomInfo.halidomRefId
end

function ModelItem:GetItem2HalidomCompoundNum(refId)
    local halidomInfo = self:GetItem2HalidomCompoundInfo(refId)
    if not halidomInfo then
        return
    end
    return halidomInfo.compoundNum
end

function ModelItem:GetEquipStrengthItem_1()
    return self._equipStrengthItemList_1
end

function ModelItem:GetEquipStrengthItem_2()
    return self._equipStrengthItemList_2
end

function ModelItem:GetItemCompoundList()
    if not self.itemCompoundList then
        self.itemCompoundList = {}
        for _, v in pairs(GameTable.PlayerItemComposeRef) do
            local data = {
                refId = v.refId,
                item1 = LxDataHelper.ParseItem_4(v.item1),
                item2 = LxDataHelper.ParseItem(v.item2),
                order = v.order,
                showMore = v.more == 1
            }
            table.insert(self.itemCompoundList, data)
        end
        table.sort(self.itemCompoundList, function(a, b)
            return a.order < b.order
        end)
    end
    return self.itemCompoundList
end

function ModelItem:CheckItemCanCompound(refId, openGetWay)
	local cfg = GameTable.PlayerItemComposeRef[refId]
	if not cfg then
		return false
	end
	local needItem = LxDataHelper.ParseItem(cfg.item2)
	for _, v in ipairs(needItem) do
		local haveNum = gModelItem:GetNumByRefId(v.itemId, nil, v.itemType)
		if haveNum < v.itemNum then
            if openGetWay then
                gModelGeneral:OpenGetWayWnd({ itemId = v.itemId, srcWnd = "UISubItemCompound" })
            end
			return false
		end
	end
	return true
end

function ModelItem:GetItemCompoundRedPoint()
    for _, v in pairs(GameTable.PlayerItemComposeRef) do
        if self:CheckItemCanCompound(v.refId) then
            return true
        end
    end
    return false
end

function ModelItem:GetMaxCompundNum(refId)
	local cfg = GameTable.PlayerItemComposeRef[refId]
	if not cfg then
		return 0
	end
    local needItem = LxDataHelper.ParseItem(cfg.item2)
    local temp
    for _, v in ipairs(needItem) do
        local haveNum = gModelItem:GetNumByRefId(v.itemId, nil, v.itemType)
        local num = math.floor(haveNum / v.itemNum)
        temp = temp == nil and num or math.min(temp, num)
    end
    return temp or 0
end

function ModelItem:ItemComposeReq(refId, num)
    local pb = LProtoHelper.CreateProto(LProtoIds.ItemComposeReq)
    pb.refId = refId
    pb.num = num
    SendMessage(pb, LProtoIds.ItemComposeReq)
end

